1	/*
2	* @info Main Memory Controller
3	*
4	* @author VLSI Lab, EE dept., Democritus University of Thrace
5	*
6	* @param L2_BLOCK_DW    : # of L2 Cache Block Bits (default 512 bits)
7	* @param L2_ENTRIES     : # of L2 Entries (default 512 entries)
8	* @param ADDRESS_BITS   : # of Address Bits (default 32 bits)
9	* @param ICACHE_BLOCK_DW: # of ICache Block Bits (default 256 bits)
10	* @param DCACHE_BLOCK_DW: # of DCache Block Bits (default 256 bits)
11	* @param FILE_NAME      : File Name containing the memory contents
12	*/
13	typedef struct packed {
14	    logic           read_icache ;
15	    logic           read_dcache ;
16	    logic           write_dcache;
17	    logic [ 32-1:0] address     ;
18	    logic [256-1:0] data        ;
19	} SavedEntry;
20	//DEFAULT: 512 blocks * 512 bits/block = 32KB Cache size
21	module main_memory #(
22	    parameter L2_BLOCK_DW     = 128 ,
23	    parameter L2_ENTRIES      = 2048,
24	    parameter ADDRESS_BITS    = 32  ,
25	    parameter ICACHE_BLOCK_DW = 256 ,
26	    parameter DCACHE_BLOCK_DW = 256 ,
27	    parameter REALISTIC       = 1   ,
28	    parameter DELAY_CYCLES    = 50  ,
29	    parameter FILE_NAME       = "memory.txt"
30	) (
31	    input  logic                       clk              ,
32	    input  logic                       rst_n            ,
33	    //Read Request Input from ICache
34	    input  logic                       icache_valid_i   ,
35	    input  logic [               31:0] icache_address_i ,
36	    //Read Request Input from DCache
37	    input  logic                       dcache_valid_i   ,
38	    input  logic [               31:0] dcache_address_i ,
39	    //Write Request Input from DCache
40	    input  logic                       dcache_valid_wr  ,
41	    input  logic [               31:0] dcache_address_wr,
42	    input  logic [DCACHE_BLOCK_DW-1:0] dcache_data_wr   ,
43	    //Output to ICache
44	    output logic                       icache_valid_o   ,
45	    output logic [ICACHE_BLOCK_DW-1:0] icache_data_o    ,
46	    //Output to DCache
47	    output logic                       dcache_valid_o   ,
48	    output logic [               31:0] dcache_address_o ,
49	    output logic [DCACHE_BLOCK_DW-1:0] dcache_data_o
50	);
51	//-------------------------------------------------------------------------------------
52	    localparam OFFSET_BITS   = $clog2(L2_BLOCK_DW/8);
53	    localparam INDEX_BITS    = $clog2(L2_ENTRIES);
54	    localparam TAG_BITS      = ADDRESS_BITS-OFFSET_BITS-INDEX_BITS;
55	    localparam DBLOCK_OFFSET = $clog2(L2_BLOCK_DW/DCACHE_BLOCK_DW);
56	    localparam IBLOCK_OFFSET = $clog2(L2_BLOCK_DW/ICACHE_BLOCK_DW);
57	    // #Internal Signals#
58	    logic      [    L2_BLOCK_DW-1:0] ram               [L2_ENTRIES-1:0];
59	    logic      [ICACHE_BLOCK_DW-1:0] data_picked_icache                ;
60	    logic      [DCACHE_BLOCK_DW-1:0] data_picked_dcache                ;
61	    SavedEntry                       input_entry_1, input_entry_2, output_entry;
62	    logic                            push_1, push_2, ready_1, ready_2, valid, pop, counter_active;
63	    logic      [   DELAY_CYCLES-1:0] delay_counter                     ;
64	    logic      [     INDEX_BITS-1:0] line_selector                     ;
65	    logic      [  DBLOCK_OFFSET-1:0] dblock_offset                     ;
66	    logic      [  IBLOCK_OFFSET-1:0] iblock_offset                     ;
67	    logic      [    L2_BLOCK_DW-1:0] block_selected, starting_bit_ic, starting_bit_dc;
68	    logic                            delayed_valid                     ;
69	    initial begin
70	        //Open the File
71	        $readmemh(FILE_NAME,ram);
72	        $display("first inst: %h",ram[0][31:0]);
73	        $display("sec inst: %h",ram[0][63:32]);
74	    end
75	    //Create the New Inputs
76	    assign input_entry_1.data = dcache_data_wr;
77	    assign input_entry_2.data = dcache_data_wr;
78	    always_comb begin : CreateNewEntries
79	        if(icache_valid_i) begin
80	            push_1 = 1;
81	            input_entry_1.read_icache = 1;
82	            input_entry_1.read_dcache = 0;
83	            input_entry_1.write_dcache = 0;
84	            input_entry_1.address = icache_address_i;
85	            if(dcache_valid_i) begin
86	                push_2 = 1;
87	                input_entry_2.read_icache = 0;
88	                input_entry_2.read_dcache = 1;
89	                input_entry_2.write_dcache = 0;
90	                input_entry_2.address = dcache_address_i;
91	            end else if(dcache_valid_wr) begin
92	                push_2 = 1;
93	                input_entry_2.read_icache = 0;
94	                input_entry_2.read_dcache = 0;
95	                input_entry_2.write_dcache = 1;
96	                input_entry_2.address = dcache_address_wr;
97	            end else begin
98	                push_2 = 0;
99	                input_entry_2.read_icache = 0;
100	                input_entry_2.read_dcache = 0;
101	                input_entry_2.write_dcache = 0;
102	                input_entry_2.address = dcache_address_wr;
103	            end
104	        end else begin
105	            //No ICache Request
106	            push_2 = 0;
107	            input_entry_2.read_icache = 0;
108	            input_entry_2.read_dcache = 0;
109	            input_entry_2.write_dcache = 0;
110	            input_entry_2.address = dcache_address_wr;
111	            if(dcache_valid_i) begin
112	                push_1 = 1;
113	                input_entry_1.read_icache = 0;
114	                input_entry_1.read_dcache = 1;
115	                input_entry_1.write_dcache = 0;
116	                input_entry_1.address = dcache_address_i;
117	            end else if(dcache_valid_wr) begin
118	                push_1 = 1;
119	                input_entry_1.read_icache = 0;
120	                input_entry_1.read_dcache = 0;
121	                input_entry_1.write_dcache = 1;
122	                input_entry_1.address = dcache_address_wr;
123	            end else begin
124	                push_1 = 0;
125	                input_entry_1.read_icache = 0;
126	                input_entry_1.read_dcache = 0;
127	                input_entry_1.write_dcache = 0;
128	                input_entry_1.address = dcache_address_wr;
129	            end
130	        end
131	    end
132	    //FiFo to store the Requests
133	    fifo_dual_ported #(
134	        .DW         ($bits(input_entry_1)),
135	        .DEPTH      (8)
136	        )
137	    instruction_queue  (
138	        .clk            (clk),
139	        .rst            (~rst_n),
140	
141	        .valid_flush    (1'b0),             //No Flush Functionality            
142	
143	        .push_1         (push_1),
144	        .ready_1        (ready_1),
145	        .push_data_1    (input_entry_1),
146	 
147	        .push_2         (push_2),
148	        .ready_2        (ready_2),
149	        .push_data_2    (input_entry_2),
150	
151	        .pop_data_1     (output_entry),
152	        .valid_1        (valid),
153	        .pop_1          (pop),
154	
155	        .pop_data_2     (),             //NC         
156	        .valid_2        (),             //NC
157	        .pop_2          (1'b0)          //Single Serve each Cycle
158	    );
159	    //Input Some Delay to immitate a more realistic L2
160	    always_ff @(posedge clk or negedge rst_n) begin : delay
161	        if(!rst_n) begin
162	            delay_counter  <= 1;
163	            counter_active <= 1'b0;
164	        end else begin
165	            case (counter_active)
166	                1'b1 : if(~|delay_counter) begin
167	                    counter_active <= 1'b0;
168	                end else begin
169	                    delay_counter <= delay_counter << 1;
170	                end
171	                1'b0 : if(valid) begin
172	                    counter_active <= 1'b1;
173	                    delay_counter  <= 1;
174	                end
175	            endcase
176	        end
177	    end
178	    //Choose Memory Model (perfect <> 50 cycles access delay)
179	    generate
180	        if(REALISTIC) begin
181	            assign delayed_valid = counter_active & ~|delay_counter;
182	        end else begin
183	            assign delayed_valid = valid;
184	        end
185	    endgenerate
186	    //Create the Output Signals
187	    assign pop              = delayed_valid;
188	    assign icache_valid_o   = delayed_valid & output_entry.read_icache;
189	    assign icache_data_o    = data_picked_icache;
190	    assign dcache_valid_o   = delayed_valid & output_entry.read_dcache;
191	    assign dcache_address_o = output_entry.address;
192	    assign dcache_data_o    = data_picked_dcache;
193	
194	    assign line_selector    = output_entry.address[OFFSET_BITS+INDEX_BITS-1 : OFFSET_BITS];
195	    assign block_selected   = ram[line_selector];
196	
197	    assign iblock_offset      = output_entry.address[OFFSET_BITS-1:OFFSET_BITS-IBLOCK_OFFSET];
198	    assign dblock_offset      = output_entry.address[OFFSET_BITS-1:OFFSET_BITS-DBLOCK_OFFSET];
199	    assign starting_bit_ic    = iblock_offset << $clog2(ICACHE_BLOCK_DW);
200	    assign starting_bit_dc    = dblock_offset << $clog2(DCACHE_BLOCK_DW);
201	    assign data_picked_icache = block_selected[starting_bit_ic +: ICACHE_BLOCK_DW];
202	    assign data_picked_dcache = block_selected[starting_bit_dc +: DCACHE_BLOCK_DW];
203	
204	    always_ff @(posedge clk) begin : RamManagement
205	        if(delayed_valid & output_entry.write_dcache) begin
206	            ram[line_selector][starting_bit_dc +: DCACHE_BLOCK_DW] <= output_entry.data;
207	        end
208	    end
209	
210	endmodule

