1	/*
2	 * @info Data Cache Top Module
3	 * @info Sub-Modules: sram.sv, data_operation.sv, ld_st_buffer.sv, wait_buffer.sv
4	 *
5	 * @author VLSI Lab, EE dept., Democritus University of Thrace
6	 *
7	 * @brief Non-Blocking Data Cache
8	 *
9	 * @note  Cache configuration: {Valid}{Dirty}[Tag][Data]
10	 *
11	 * @param DATA_WIDTH    : # of Data Bits
12	 * @param ADDR_BITS     : # of Address Bits
13	 * @param R_WIDTH       : # of Register Bits
14	 * @param MICROOP       : # of Microoperation Bits
15	 * @param ROB_TICKET    : # of Rob's ticket Bits
16	 * @param ASSOCIATIVITY : # of Ways in the DATA CACHE
17	 * @param ENTRIES       : # of Blocks per Way
18	 * @param BLOCK_WIDTH   : # of Block Bits
19	 * @param BUFFER_SIZES  : # of Entries in the Buffers (Load/Store/Wait) (affects miss_under_miss performance)
20	 */
21	`ifdef MODEL_TECH
22	    `include "structs.sv"
23	    `include "vstructs.sv"
24	`endif
25	module data_cache #(
26	    parameter DATA_WIDTH           = 32 ,
27	    parameter ADDR_BITS            = 32 ,
28	    parameter R_WIDTH              = 6  ,
29	    parameter MICROOP              = 5  ,
30	    parameter ROB_TICKET           = 3  ,
31	    parameter ASSOCIATIVITY        = 4  ,
32	    parameter ENTRIES              = 256,
33	    parameter BLOCK_WIDTH          = 256,
34	    parameter BUFFER_SIZES         = 4  ,
35	    parameter VECTOR_ENABLED       = 1  ,
36	    parameter VECTOR_MICROOP_WIDTH = 7  ,
37	    parameter VECTOR_REQ_WIDTH     = 256,
38	    parameter VECTOR_LANES         = 8
39	) (
40	    input  logic                   clk                 ,
41	    input  logic                   rst_n               ,
42	    input  logic                   output_used         ,
43	    //Load Input Port
44	    input  logic                   load_valid          ,
45	    input  logic [  ADDR_BITS-1:0] load_address        ,
46	    input  logic [    R_WIDTH-1:0] load_dest           ,
47	    input  logic [    MICROOP-1:0] load_microop        ,
48	    input  logic [ ROB_TICKET-1:0] load_ticket         ,
49	    //Store Input Port
50	    input  logic                   store_valid         ,
51	    input  logic [  ADDR_BITS-1:0] store_address       ,
52	    input  logic [ DATA_WIDTH-1:0] store_data          ,
53	    input  logic [    MICROOP-1:0] store_microop       ,
54	    //Vector Req Input Port
55	    input  logic                   mem_req_valid_i     ,
56	    input  vector_mem_req          mem_req_i           ,
57	    output logic                   cache_vector_ready_o,
58	    //Request Write Port to L2
59	    output logic                   write_l2_valid      ,
60	    output logic [  ADDR_BITS-1:0] write_l2_addr       ,
61	    output logic [BLOCK_WIDTH-1:0] write_l2_data       ,
62	    //Request Read Port to L2
63	    output logic                   request_l2_valid    ,
64	    output logic [  ADDR_BITS-1:0] request_l2_addr     ,
65	    //Update Port from L2
66	    input  logic                   update_l2_valid     ,
67	    input  logic [  ADDR_BITS-1:0] update_l2_addr      ,
68	    input  logic [BLOCK_WIDTH-1:0] update_l2_data      ,
69	    //Output Port
70	    output logic                   cache_blocked       ,
71	    output logic                   cache_will_block    ,
72	    output ex_update               served_output       ,
73	    //Vector Output Port
74	    output logic                   vector_resp_valid_o ,
75	    output vector_mem_resp         vector_resp
76	);
77	    //Local Parameter
78	    localparam OUTPUT_BITS = $clog2(ASSOCIATIVITY);
79	    localparam INDEX_BITS  = $clog2(ENTRIES);
80	    localparam OFFSET_BITS = $clog2(BLOCK_WIDTH/DATA_WIDTH)+2;
81	    localparam TAG_BITS = ADDR_BITS - INDEX_BITS - OFFSET_BITS;
82	
83	    // #Internal Signals#
84	    logic [ROB_TICKET-1:0] ld_head_ticket, wt_s_ticket, wt_w_ticket;
85	    logic [ ADDR_BITS-1:0] ld_head_addr, st_head_addr, wt_w_address, saved_search_addr, served_address, wt_search_addr, search_address_o;
86	    logic [DATA_WIDTH-1:0] st_head_data, wt_s_data, wt_s_frw_data, wt_w_data, st_s_data, served_data;
87	    logic [   MICROOP-1:0] ld_head_microop, st_head_microop, wt_s_microop, wt_w_microop,  served_microop;
88	    logic [   R_WIDTH-1:0] ld_head_dest, wt_s_dest, wt_w_dest;
89	    logic                  ld_ready, ld_valid, st_ready, st_valid, wt_ready, wt_valid, wt_in_walk;
90	    logic                  ld_pop, ld_push, st_pop, st_push, store_isfetched, wt_push;
91	    logic                  ld_head_isfetched, st_head_isfetched;
92	    logic                  wt_invalidate, wt_found_one, wt_s_frw_hit, wt_s_isstore, wt_w_isstore;
93	    logic                  ld_s_phit, st_s_vhit, st_s_phit, served_exc_v;
94	
95	    logic [ASSOCIATIVITY-1 : 0][BLOCK_WIDTH-1 : 0]  data, overwritten_data;
96	    logic [ASSOCIATIVITY-1 : 0][TAG_BITS-1 : 0]     tag, overwritten_tag;
97	    logic [ASSOCIATIVITY-1 : 0][ENTRIES-1:0]        validity, dirty;
98	    logic [$clog2(ASSOCIATIVITY)-1 : 0]             entry_used;
99	    logic [   INDEX_BITS-1 : 0] read_line_select, write_line_select;
