322	    //Pick the correct Data and Serve
323	    always_comb begin : DataServe
324	        if(serve==LD_IN) begin
325	            if(wt_s_frw_hit) begin
326	                //Forward from Wait Buffer
327	                served     = 1'b1;
328	                must_wait  = 1'b0;
329	                lru_update = 1'b0;
330	                served_output.data = wt_s_frw_data;
331	            end else if(st_s_vhit) begin
332	                //Forward from Store Buffer
333	                served     = 1'b1;
334	                must_wait  = 1'b0;
335	                lru_update = 1'b0;
336	                served_output.data = st_s_data;
337	            end else if(Hit) begin
338	                //Grab from Cache
339	                served     = 1'b1;
340	                must_wait  = 1'b0;
341	                lru_update = 1'b1;
342	                served_output.data = served_data;
343	            end else begin
344	                //Can not Serve
345	                served     = 1'b0;
346	                lru_update = 1'b0;
347	                served_output.data = served_data;
348	                if(st_s_phit | ld_s_phit) begin
349	                //Store in Wait Buffer
350	                    must_wait = 1'b1;
351	                end else begin
352	                //Store in Load Buffer
353	                    must_wait = 1'b0;
354	                end
355	            end
356	        end else if(serve==ST_IN) begin
357	            served_output.data = served_data;
358	            if(update_l2_valid) begin
359	                //Write Conflict.. Store will wait in Buffers
360	                served     = 1'b0;
361	                lru_update = 1'b0;
362	                if(st_s_phit | ld_s_phit) begin
363	                    //Store in Wait Buffer
364	                    must_wait = 1'b1;
365	                end else begin
366	                    //Store in Store Buffer
367	                    must_wait = 1'b0;
368	                end
369	            end else begin
370	                //Serve the Store
371	                if(st_s_phit) begin
372	                    //Previous Store was in ST Buffer.. Must wait in Wait Buffer
373	                    served     = 1'b0;
374	                    must_wait  = 1'b1;
375	                    lru_update = 1'b0;
376	                end else if(Hit) begin
377	                    //If Hit Serve Normally
378	                    served     = 1'b1;
379	                    must_wait  = 1'b0;
380	                    lru_update = 1'b1;
381	                end else if(ld_s_phit) begin
382	                    //If load in LD Buffer, store in Wait Buffer
383	                    served     = 1'b0;
384	                    must_wait  = 1'b1;
385	                    lru_update = 1'b0;
386	                end else begin
387	                    //Store in Store Buffer
388	                    served     = 1'b0;
389	                    must_wait  = 1'b0;
390	                    lru_update = 1'b0;
391	                end
392	            end
393	        end else if(serve==LD) begin
394	            served     = 1'b1;
395	            must_wait  = 1'b0;
396	            lru_update = 1'b1;
397	            served_output.data = served_data;
398	        end else if(serve==ST) begin
399	            served     = 1'b1;
400	            must_wait  = 1'b0;
401	            lru_update = 1'b1;
402	            served_output.data = served_data;
403	        end else if (serve==WT) begin
404	            served     = 1'b1;
405	            must_wait  = 1'b0;
406	            lru_update = 1'b1;
407	            served_output.data = served_data;
408	        end else if (serve==VCT_LD) begin
409	            served     = Hit;
410	            must_wait  = 1'b0;
411	            lru_update = Hit;
412	            served_output.data = served_data;
413	        end else if (serve==VCT_LD) begin
414	            served     = Hit;
415	            must_wait  = 1'b0;
416	            lru_update = Hit;
417	            served_output.data = served_data;
418	        end else begin
419	            served     = 1'b0;
420	            must_wait  = 1'b0;
421	            lru_update = 1'b0;
422	            served_output.data = served_data;
423	        end
424	    end
