612	    //Initialize the Operations Module
613	    data_operation #(
614	        .ADDR_W     (OFFSET_BITS),
615	        .DATA_W     (DATA_WIDTH),
616	        .MICROOP    (MICROOP),
617	        .BLOCK_W    (BLOCK_WIDTH),
618	        .LOAD_ONLY  (0)
619	        )
620	    data_operation  (
621	        .input_address  (offset_select),
622	        .input_block    (block_picked),
623	        .input_data     (data_picked),
624	        .microop        (served_microop),
625	
626	        .valid_exc      (served_exc_v),
627	        .exception      (served_exc),
628	        .output_block   (scalar_new_modded_block),
629	        .output_vector  (served_data)
630	        );
631	
632	    assign ld_pop  = (serve==LD);
633	    assign ld_push = (serve==LD_IN) & ~served & ~must_wait & ~ld_s_phit;
634	    //Initialize the Load Buffer
635	    ld_st_buffer #(
636	        .DATA_WIDTH     (DATA_WIDTH),
637	        .ADDR_BITS      (ADDR_BITS),
638	        .BLOCK_ID_START (OFFSET_BITS),
639	        .R_WIDTH        (R_WIDTH),
640	        .MICROOP        (MICROOP),
641	        .ROB_TICKET     (ROB_TICKET),
642	        .DEPTH          (BUFFER_SIZES))
643	    load_buffer (
644	        .clk                (clk),
645	        .rst_n              (rst_n),
646	
647	        .push               (ld_push),
648	        .write_address      (load_address),
649	        .write_data         (),             //NC
650	        .write_microop      (load_microop),
651	        .write_dest         (load_dest),
652	        .write_ticket       (load_ticket),
653	        .write_isfetched    (1'b0),
654	
655	        .search_address     (served_address),
656	        .search_microop_in  (),             //NC
657	        .search_data        (),             //NC
658	        .search_microop     (),             //NC
659	        .search_dest        (),             //NC
660	        .search_ticket      (),             //NC
661	        .search_valid_hit   (),             //NC
662	        .search_partial_hit (ld_s_phit),
663	
664	        .valid_update       (update_l2_valid),
665	        .update_address     (update_l2_addr),
666	
667	        .pop                (ld_pop),
668	        .head_isfetched     (ld_head_isfetched),
669	        .head_address       (ld_head_addr),
670	        .head_data          (),             //NC
671	        .head_microop       (ld_head_microop),
672	        .head_dest          (ld_head_dest),
673	        .head_ticket        (ld_head_ticket),
674	
675	        .valid              (ld_valid),
676	        .ready              (ld_ready)
677	        );
678	
679	
680	    assign st_pop  = (serve==ST);
681	    assign st_push = (serve==ST_IN & ~served & ~must_wait & ~st_s_phit);
682	    //Initialize the Store Buffer
683	    ld_st_buffer #(
684	        .DATA_WIDTH     (DATA_WIDTH),
685	        .ADDR_BITS      (ADDR_BITS),
686	        .BLOCK_ID_START (OFFSET_BITS),
687	        .R_WIDTH        (R_WIDTH),
688	        .MICROOP        (MICROOP),
689	        .ROB_TICKET     (ROB_TICKET),
690	        .DEPTH          (BUFFER_SIZES))
691	    store_buffer (
692	        .clk                (clk),
693	        .rst_n              (rst_n),
694	
695	        .push               (st_push),
696	        .write_address      (store_address),
697	        .write_data         (store_data),
698	        .write_microop      (store_microop),
699	        .write_dest         (),             //NC
700	        .write_ticket       (),             //NC
701	        .write_isfetched    (Hit),
702	
703	        .search_address     (served_address),
704	        .search_microop_in  (served_microop),
705	        .search_data        (st_s_data),
706	        .search_microop     (),             //NC
707	        .search_dest        (),             //NC
708	        .search_ticket      (),             //NC
709	        .search_valid_hit   (st_s_vhit),
710	        .search_partial_hit (st_s_phit),
711	
712	        .valid_update       (update_l2_valid),
713	        .update_address     (update_l2_addr),
714	
715	        .pop                (st_pop),
716	        .head_isfetched     (st_head_isfetched),
717	        .head_address       (st_head_addr),
718	        .head_data          (st_head_data),
719	        .head_microop       (st_head_microop),
720	        .head_dest          (),             //NC
721	        .head_ticket        (),             //NC
722	
723	        .valid              (st_valid),
724	        .ready              (st_ready)
725	        );
726	
727	    //Enter in WT Buffer Serve Mode
728	    assign wt_invalidate = (serve==LD | serve==ST) & wt_found_one;
729	    //Save the Search Address
730	    always_ff @(posedge clk) begin : SavedSearch
731	        if(serve==LD && wt_found_one) begin
732	                saved_search_addr <= ld_head_addr;
733	        end else if(serve==ST && wt_found_one) begin
734	            saved_search_addr <= st_head_addr;
735	        end
736	    end
737	
738	    always_comb begin : WaitBufferInputs
739	        wt_w_dest   = load_dest;
740	        wt_w_ticket = load_ticket;
741	        wt_w_data   = store_data;
742	        if(serve==LD_IN) begin
743	            wt_w_address = load_address;
744	            wt_w_microop = load_microop;
745	        end else begin
746	            wt_w_address = store_address;
747	            wt_w_microop = store_microop;
748	        end
749	    end
750	
751	    assign wt_w_isstore   = (serve==ST_IN);
752	    assign wt_push        = (serve==LD_IN & ~served & must_wait) | (serve==ST_IN & ~served & must_wait);
753	    assign wt_search_addr = (serve==WT) ? saved_search_addr: served_address;
754	    //Initialize the Wait Buffer
755	    wait_buffer #(
756	        .DATA_WIDTH         (DATA_WIDTH),
757	        .ADDR_BITS          (ADDR_BITS),
758	        .R_WIDTH            (R_WIDTH),
759	        .MICROOP            (MICROOP),
760	        .ROB_TICKET         (ROB_TICKET),
761	        .DEPTH              (2*BUFFER_SIZES)
762	        )
763	    wait_buffer  (
764	        .clk                (clk),
765	        .rst_n              (rst_n),
766	
767	        .write_enable       (wt_push),
768	        .write_is_store     (wt_w_isstore),
769	        .write_address      (wt_w_address),
770	        .write_data         (wt_w_data),
771	        .write_microop      (wt_w_microop),
772	        .write_dest         (wt_w_dest),
773	        .write_ticket       (wt_w_ticket),
774	
775	        .search_invalidate  (wt_invalidate),
776	        .search_address     (wt_search_addr),
777	        .search_microop_in  (served_microop),
778	        .search_address_o   (search_address_o),
779	        .search_is_store    (wt_s_isstore),
780	        .search_data        (wt_s_data),
781	        .search_frw_data    (wt_s_frw_data),
782	        .search_microop     (wt_s_microop),
783	        .search_dest        (wt_s_dest),
784	        .search_ticket      (wt_s_ticket),
785	        .search_valid_hit   (wt_s_frw_hit),
786	
787	        .valid              (wt_valid),
788	        .ready              (wt_ready),
789	        .search_found_one   (wt_found_one),
790	        .search_found_multi (),             //NC
791	        .in_walk_mode       (wt_in_walk)
792	        );
793	
794	    generate if(VECTOR_ENABLED) begin: g_vector_buffer
795	        localparam SIZE_WIDTH = $clog2(VECTOR_REQ_WIDTH/8)+1;
796	
797	        logic [  VECTOR_REQ_WIDTH-1:0] vct_head_data              ;
798	        logic [        SIZE_WIDTH-1:0] vct_head_size              ;
799	        logic [        INDEX_BITS-1:0] line_select_a              ;
800	        logic [        INDEX_BITS-1:0] line_select_b              ;
801	        logic [     2*BLOCK_WIDTH-1:0] block_picked_double        ;
802	        logic [     2*BLOCK_WIDTH-1:0] vct_new_modded_block_double;
803	        logic [$clog2(VECTOR_LANES):0] vct_head_ticket            ;
804	        logic                          nxt_multi_fetches_needed   ;
805	        logic                          multi_fetches_needed       ;
806	        logic                          multi_fetches_en           ;
807	        logic                          vct_push                   ;
808	        logic                          vct_pop                    ;
809	
810	        assign Hit_a    = Hit;
811	        assign vct_push = mem_req_valid_i & cache_vector_ready_o;
812	        assign vct_pop  = (multi_fetches_needed | nxt_multi_fetches_needed) ? (serve===VCT_ST | serve===VCT_LD) & Hit_a & Hit_b :
813	                                                                              (serve===VCT_ST | serve===VCT_LD) & Hit_a;
814	        //Calculate if the data span in two cache lines
815	        assign vct_head_addr_b          = vct_head_addr + vct_head_size -1;
816	        assign line_select_a            = vct_head_addr[OFFSET_BITS+INDEX_BITS-1 : OFFSET_BITS];
817	        assign line_select_b            = vct_head_addr_b[OFFSET_BITS+INDEX_BITS-1 : OFFSET_BITS];
818	        assign nxt_multi_fetches_needed = (line_select_a !== line_select_b); //check if the last byte of the transfer is in a different cache line
819	
820	        assign multi_fetches_en = ~multi_fetches_needed & (serve===VCT_ST | serve===VCT_LD);
821	        always_ff @(posedge clk or negedge rst_n) begin : proc_multi_fetch_FSM
822	            if(~rst_n) begin
823	                multi_fetches_needed <= 1'b0;
824	            end else if (multi_fetches_en) begin
825	                multi_fetches_needed <= nxt_multi_fetches_needed;
826	            end else if (multi_fetches_needed & vct_pop) begin
827	                multi_fetches_needed <= 1'b0;
828	            end
829	        end
830	        // Maintain the FSM tracking multi-line fetches
831	        assign vct_request_a = (serve===VCT_ST | serve===VCT_LD) & ~Hit_a & ~vct_head_requested[0];
832	        assign vct_request_b = (serve===VCT_ST | serve===VCT_LD) & (vct_head_requested[0] | Hit_a) & ~vct_head_requested[1] & (multi_fetches_needed | nxt_multi_fetches_needed);
833	        always_ff @(posedge clk or negedge rst_n) begin : proc_head_requested
834	            if(~rst_n) begin
835	                vct_head_requested <= '0;
836	            end else begin
837	                if(vct_pop) begin
838	                    vct_head_requested <= '0;
839	                end else if(vct_request_a) begin
840	                    vct_head_requested[0] <= 1'b1;
841	                end else if(vct_request_b) begin
842	                    vct_head_requested <= 2'b11;
843	                end
844	            end
845	        end
846	        vld_st_buffer #(
847	            .DATA_WIDTH    (VECTOR_REQ_WIDTH      ),
848	            .ADDR_BITS     (ADDR_BITS             ),
849	            .BLOCK_ID_START(OFFSET_BITS           ),
850	            .MICROOP_WIDTH (VECTOR_MICROOP_WIDTH  ),
851	            .TICKET_WIDTH  ($clog2(VECTOR_LANES)+1),
852	            .SIZE_WIDTH    (SIZE_WIDTH            ),
853	            .DEPTH         (4                     )
854	        ) vld_st_buffer (
855	            .clk             (clk                 ),
856	            .rst_n           (rst_n               ),
857	
858	            .push            (vct_push            ),
859	            .write_address   (mem_req_i.address   ),
860	            .write_data      (mem_req_i.data      ),
861	            .write_ticket    (mem_req_i.ticket    ),
862	            .write_size      (mem_req_i.size      ),
863	            .write_microop   (mem_req_i.microop   ),
864	
865	            .valid_update_i  (update_l2_valid     ),
866	            .update_address_i(update_l2_addr      ),
867	
868	            .valid_o         (vct_valid           ),
869	            .ready_o         (cache_vector_ready_o),
870	            .pop             (vct_pop             ),
871	            .head_is_store   (vct_head_isstore    ),
872	            .head_is_fetched (                    ),
873	            .head_address    (vct_head_addr       ),
874	            .head_data       (vct_head_data       ),
875	            .head_microop    (vct_head_microop    ),
876	            .head_ticket     (vct_head_ticket     ),
877	            .head_size       (vct_head_size       )
878	        );
879	
880	        assign block_picked_double = {block_picked_b,block_picked};
881	        vdata_operation #(
882	            .ADDR_W   (OFFSET_BITS         ),
883	            .DATA_W   (VECTOR_REQ_WIDTH    ),
884	            .MICROOP_W(VECTOR_MICROOP_WIDTH),
885	            .SIZE_W   (SIZE_WIDTH          ),
886	            .BLOCK_W  (BLOCK_WIDTH         )
887	        ) vdata_operation (
888	            .clk          (clk                        ),
889	            .valid_i      (vct_pop                    ),
890	            //Inputs
891	            .input_address(offset_select              ),
892	            .input_block  (block_picked_double        ),
893	            .input_data   (vct_head_data              ),
894	            .microop      (vct_head_microop           ),
895	            .size         (vct_head_size              ),
896	            //Outputs
897	            .valid_exc    (                           ),
898	            .exception    (                           ),
899	            .output_block (vct_new_modded_block_double),
900	            .output_vector(vct_served_data            )
901	        );
902	        assign vct_new_modded_block = vct_new_modded_block_double[BLOCK_WIDTH-1:0];
903	        assign new_modded_block     = (serve === VCT_LD) | (serve === VCT_ST) ? vct_new_modded_block : scalar_new_modded_block;
904	        assign vector_resp_valid_o  = (multi_fetches_needed | nxt_multi_fetches_needed) ? serve===VCT_LD & Hit_a & Hit_b :
905	                                                                                          serve===VCT_LD & Hit_a;
906	        assign vector_resp.ticket   = vct_head_ticket;
907	        assign vector_resp.size     = vct_head_size;
908	        assign vector_resp.data     = vct_served_data;
909	
910	        // Assertion for WIP features
911	        assert property (@(posedge clk) disable iff(!rst_n | !VECTOR_ENABLED) (serve === VCT_ST) |-> !nxt_multi_fetches_needed) else $warning("WARNING:Data_Cache: Multi-line stores not yet implemented in the Data Cache");
912	    end else begin: g_stubs
913	        assign new_modded_block    = scalar_new_modded_block;
914	        assign vct_valid           = 1'b0;
915	        assign vct_head_isstore    = 1'b0;
916	        assign vector_resp_valid_o = 1'b0;
917	        assign vct_request_a       = 1'b0;
918	        assign vct_request_b       = 1'b0;
919	        assign vct_head_requested  = 2'b00;
920	    end endgenerate
921	
922	assert property (@(posedge clk) disable iff(!rst_n) load_valid |-> !store_valid) else $error("ERROR:Data_Cache: Two operations in the same cycle");
923	assert property (@(posedge clk) disable iff(!rst_n) store_valid |-> !load_valid) else $error("ERROR:Data_Cache: Two operations in the same cycle");
924	assert property (@(posedge clk) disable iff(!rst_n | !VECTOR_ENABLED) (store_valid | load_valid) |-> (!vct_valid && !mem_req_valid_i)) else $error("ERROR:Data_Cache: Cannot issue scalar mem ops while vector mem op in flight");
925	
926	
927	endmodule

