/*
 * @info Data Cache Top Module
 * @info Sub-Modules: sram.sv, data_operation.sv, ld_st_buffer.sv, wait_buffer.sv
 *
 * @author VLSI Lab, EE dept., Democritus University of Thrace
 *
 * @brief Non-Blocking Data Cache
 *
 * @note  Cache configuration: {Valid}{Dirty}[Tag][Data]
 *
 * @param DATA_WIDTH    : # of Data Bits
 * @param ADDR_BITS     : # of Address Bits
 * @param R_WIDTH       : # of Register Bits
 * @param MICROOP       : # of Microoperation Bits
 * @param ROB_TICKET    : # of Rob's ticket Bits
 * @param ASSOCIATIVITY : # of Ways in the DATA CACHE
 * @param ENTRIES       : # of Blocks per Way
 * @param BLOCK_WIDTH   : # of Block Bits
 * @param BUFFER_SIZES  : # of Entries in the Buffers (Load/Store/Wait) (affects miss_under_miss performance)
 */
`ifdef MODEL_TECH
    `include "structs.sv"
    `include "vstructs.sv"
`endif
module data_cache #(
    parameter DATA_WIDTH           = 32 ,
    parameter ADDR_BITS            = 32 ,
    parameter R_WIDTH              = 6  ,
    parameter MICROOP              = 5  ,
    parameter ROB_TICKET           = 3  ,
    parameter ASSOCIATIVITY        = 4  ,
    parameter ENTRIES              = 256,
    parameter BLOCK_WIDTH          = 256,
    parameter BUFFER_SIZES         = 4  ,
    parameter VECTOR_ENABLED       = 1  ,
    parameter VECTOR_MICROOP_WIDTH = 7  ,
    parameter VECTOR_REQ_WIDTH     = 256,
    parameter VECTOR_LANES         = 8
) (
    input  logic                   clk                 ,
    input  logic                   rst_n               ,
    input  logic                   output_used         ,
    //Load Input Port
    input  logic                   load_valid          ,
    input  logic [  ADDR_BITS-1:0] load_address        ,
    input  logic [    R_WIDTH-1:0] load_dest           ,
    input  logic [    MICROOP-1:0] load_microop        ,
    input  logic [ ROB_TICKET-1:0] load_ticket         ,
    //Store Input Port
    input  logic                   store_valid         ,
    input  logic [  ADDR_BITS-1:0] store_address       ,
    input  logic [ DATA_WIDTH-1:0] store_data          ,
    input  logic [    MICROOP-1:0] store_microop       ,
    //Vector Req Input Port
    input  logic                   mem_req_valid_i     ,
    input  vector_mem_req          mem_req_i           ,
    output logic                   cache_vector_ready_o,
    //Request Write Port to L2
    output logic                   write_l2_valid      ,
    output logic [  ADDR_BITS-1:0] write_l2_addr       ,
    output logic [BLOCK_WIDTH-1:0] write_l2_data       ,
    //Request Read Port to L2
    output logic                   request_l2_valid    ,
    output logic [  ADDR_BITS-1:0] request_l2_addr     ,
    //Update Port from L2
    input  logic                   update_l2_valid     ,
    input  logic [  ADDR_BITS-1:0] update_l2_addr      ,
    input  logic [BLOCK_WIDTH-1:0] update_l2_data      ,
    //Output Port
    output logic                   cache_blocked       ,
    output logic                   cache_will_block    ,
    output ex_update               served_output       ,
    //Vector Output Port
    output logic                   vector_resp_valid_o ,
    output vector_mem_resp         vector_resp
);
    //Local Parameter
    localparam OUTPUT_BITS = $clog2(ASSOCIATIVITY);
    localparam INDEX_BITS  = $clog2(ENTRIES);
    localparam OFFSET_BITS = $clog2(BLOCK_WIDTH/DATA_WIDTH)+2;
    localparam TAG_BITS = ADDR_BITS - INDEX_BITS - OFFSET_BITS;

    // #Internal Signals#
    logic [ROB_TICKET-1:0] ld_head_ticket, wt_s_ticket, wt_w_ticket;
    logic [ ADDR_BITS-1:0] ld_head_addr, st_head_addr, wt_w_address, saved_search_addr, served_address, wt_search_addr, search_address_o;
    logic [DATA_WIDTH-1:0] st_head_data, wt_s_data, wt_s_frw_data, wt_w_data, st_s_data, served_data;
    logic [   MICROOP-1:0] ld_head_microop, st_head_microop, wt_s_microop, wt_w_microop,  served_microop;
    logic [   R_WIDTH-1:0] ld_head_dest, wt_s_dest, wt_w_dest;
    logic                  ld_ready, ld_valid, st_ready, st_valid, wt_ready, wt_valid, wt_in_walk;
    logic                  ld_pop, ld_push, st_pop, st_push, store_isfetched, wt_push;
    logic                  ld_head_isfetched, st_head_isfetched;
    logic                  wt_invalidate, wt_found_one, wt_s_frw_hit, wt_s_isstore, wt_w_isstore;
    logic                  ld_s_phit, st_s_vhit, st_s_phit, served_exc_v;

    logic [ASSOCIATIVITY-1 : 0][BLOCK_WIDTH-1 : 0]  data, overwritten_data;
    logic [ASSOCIATIVITY-1 : 0][TAG_BITS-1 : 0]     tag, overwritten_tag;
    logic [ASSOCIATIVITY-1 : 0][ENTRIES-1:0]        validity, dirty;
    logic [$clog2(ASSOCIATIVITY)-1 : 0]             entry_used;
    logic [   INDEX_BITS-1 : 0] read_line_select, write_line_select;
    logic [  OUTPUT_BITS-1 : 0] lru_way, new_valid_entry;
    logic [ASSOCIATIVITY-1 : 0] write_en_tag, write_en_data, all_valid_temp, entry_found;
    logic [     TAG_BITS-1 : 0] new_tag, update_l2_tag, new_modded_tag, tag_usearch, tag_picked;
    logic [  BLOCK_WIDTH-1 : 0] new_data, new_modded_block, block_picked, scalar_new_modded_block;
    logic [   DATA_WIDTH-1 : 0] data_picked;
    logic [              3 : 0] served_exc;
    logic                       all_valid, lru_update, Hit, served, must_wait;

    // Second Read port related signals
    logic [ASSOCIATIVITY-1:0][BLOCK_WIDTH-1:0] data_b            ;
    logic [ASSOCIATIVITY-1:0][   TAG_BITS-1:0] tag_b             ;
    logic [   INDEX_BITS-1:0]                  read_line_select_b;
    logic [     TAG_BITS-1:0]                  tag_usearch_b     ;
    logic [ASSOCIATIVITY-1:0]                  entry_found_b     ;
    logic [  BLOCK_WIDTH-1:0]                  block_picked_b    ;
    logic                                      Hit_a, Hit_b;

    logic [    VECTOR_REQ_WIDTH-1:0] vct_served_data     ;
    logic [         BLOCK_WIDTH-1:0] vct_new_modded_block;
    logic [           ADDR_BITS-1:0] vct_head_addr       ;
    logic [           ADDR_BITS-1:0] vct_head_addr_b     ;
    logic [VECTOR_MICROOP_WIDTH-1:0] vct_head_microop    ;
    logic [                     1:0] vct_head_requested  ;
    logic                            vct_valid           ;
    logic                            vct_head_isstore    ;
    logic                            vct_request_a       ;
    logic                            vct_request_b       ;

    logic [       OFFSET_BITS-1 : 0]  offset_select;
    logic [2:0][   INDEX_BITS-1 : 0]  read_address;
    logic [ASSOCIATIVITY-1 : 0][2:0][TAG_BITS-1:0] read_tag;
    logic [ASSOCIATIVITY-1 : 0][2:0][BLOCK_WIDTH-1:0] read_data;
    //Serve FSM
    typedef enum logic [2:0] {IDLE, LD_IN, ST_IN, LD, ST, WT, VCT_LD, VCT_ST} serve_mode;
    serve_mode serve;

    //Create the Line selectors for the Data Banks Indexing
    assign read_line_select  = served_address[OFFSET_BITS+INDEX_BITS-1 : OFFSET_BITS];
    assign write_line_select = update_l2_valid ? update_l2_addr[OFFSET_BITS+INDEX_BITS-1 : OFFSET_BITS] : served_address[OFFSET_BITS+INDEX_BITS-1 : OFFSET_BITS];
    assign offset_select     = served_address[OFFSET_BITS-1 : 0];
    assign new_data          = update_l2_valid ? update_l2_data : new_modded_block;
    assign new_tag           = update_l2_valid ? update_l2_tag : new_modded_tag;                    //- same as the saved/read tag
    assign update_l2_tag     = update_l2_addr[OFFSET_BITS+INDEX_BITS +: TAG_BITS];
    assign tag_usearch       = served_address[OFFSET_BITS+INDEX_BITS +: TAG_BITS];
    //Create the Read Requests towards the L2
    assign request_l2_valid = (serve==LD_IN & ~served & ~ld_s_phit & ~st_s_phit) | (serve==ST_IN & ~served & ~st_s_phit & ~ld_s_phit & ~Hit) |
                              vct_request_a | vct_request_b;
    assign request_l2_addr  = vct_request_a ? vct_head_addr   :
                              vct_request_b ? vct_head_addr_b :
                                              served_address;
    //Create the Write Requests towards the L2
    assign write_l2_valid = update_l2_valid & all_valid & dirty[lru_way][write_line_select];
    assign write_l2_addr  = {overwritten_tag[lru_way],write_line_select};
    assign write_l2_data  = overwritten_data[lru_way];

    assign cache_will_block = wt_invalidate;
    //Create the Output
    always_comb begin : CreateOutput
        if(serve==LD_IN) begin
            served_output.valid = served;
            served_output.destination = load_dest;
            served_output.ticket = load_ticket;
            served_output.valid_exception = served_exc_v;
            served_output.cause = served_exc;
        end else if(serve==ST_IN) begin
            served_output.valid = 1'b0;
            served_output.destination = load_dest;
            served_output.ticket = load_ticket;
            served_output.valid_exception = served_exc_v;
            served_output.cause = served_exc;
        end else if(serve==LD) begin
            served_output.valid = 1'b1;
            served_output.destination = ld_head_dest;
            served_output.ticket = ld_head_ticket;
            served_output.valid_exception = served_exc_v;
            served_output.cause = served_exc;
        end else if(serve==ST) begin
            served_output.valid = 1'b0;
            served_output.destination = load_dest;
            served_output.ticket = load_ticket;
            served_output.valid_exception = served_exc_v;
            served_output.cause = served_exc;
        end else if(serve==WT) begin
            served_output.valid = ~wt_s_isstore;
            served_output.destination = wt_s_dest;
            served_output.ticket = wt_s_ticket;
            served_output.valid_exception = served_exc_v;
            served_output.cause = served_exc;
        end else begin
            served_output.valid = 1'b0;
            served_output.destination = load_dest;
            served_output.ticket = load_ticket;
            served_output.valid_exception = served_exc_v;
            served_output.cause = served_exc;
        end
    end

    //SRAM TAG-DATA BANKS
    //Generate the Cache Banks(accessed in parallel) : ( 1 Bank for Tags and 1 Bank for Data ) per way
    genvar i;
    generate if (VECTOR_ENABLED) begin : g_cache_big
        assign read_address[0] = read_line_select;
        assign read_address[1] = write_line_select;
        assign read_address[2] = read_line_select_b;
        for (i = 0; i < ASSOCIATIVITY ; i = i + 1) begin
            assign tag[i]             = read_tag[i][0];
            assign overwritten_tag[i] = read_tag[i][1];
            assign tag_b[i]           = read_tag[i][2];
            assign data[i]            = read_data[i][0];
            assign overwritten_data[i]= read_data[i][1];
            assign data_b[i]          = read_data[i][2];
            // Initialize the Tag Banks for each Set    -> Outputs the saved Tags
            sram #(.SIZE        (ENTRIES),
                   .DATA_WIDTH  (TAG_BITS),
                   .RD_PORTS    (3),
                   .WR_PORTS    (1),
                   .RESETABLE   (0))
            sram_tag(.clk                  (clk),
                     .rst_n                (rst_n),
                     .read_address         (read_address),
                     .data_out             (read_tag[i]),
                     .Wr_En                (write_en_tag[i]),
                     .write_address        (write_line_select),
                     .new_data             (new_tag));
            // Initialize the Data Banks for each Set   -> Outputs the saved Data
            sram #(.SIZE        (ENTRIES),
                   .DATA_WIDTH  (BLOCK_WIDTH),
                   .RD_PORTS    (3),
                   .WR_PORTS    (1),
                   .RESETABLE   (0))
            sram_data(.clk                  (clk),
                      .rst_n                (rst_n),
                      .read_address         (read_address),
                      .data_out             (read_data[i]),
                      .Wr_En                (write_en_data[i]),
                      .write_address        (write_line_select),
                      .new_data             (new_data));
        end
    end else begin : g_cache_small
        assign read_address[0] = read_line_select;
        assign read_address[1] = write_line_select;
        for (i = 0; i < ASSOCIATIVITY ; i = i + 1) begin
            assign tag[i]             = read_tag[i][0];
            assign overwritten_tag[i] = read_tag[i][1];
            assign data[i]            = read_data[i][0];
            assign overwritten_data[i]= read_data[i][1];
            // Initialize the Tag Banks for each Set    -> Outputs the saved Tags
            sram #(.SIZE        (ENTRIES),
                   .DATA_WIDTH  (TAG_BITS),
                   .RD_PORTS    (2),
                   .WR_PORTS    (1),
                   .RESETABLE   (0))
            sram_tag(.clk                  (clk),
                     .rst_n                (rst_n),
                     .read_address         (read_address),
                     .data_out             (read_tag[i]),
                     .Wr_En                (write_en_tag[i]),
                     .write_address        (write_line_select),
                     .new_data             (new_tag));
            // Initialize the Data Banks for each Set   -> Outputs the saved Data
            sram #(.SIZE        (ENTRIES),
                   .DATA_WIDTH  (BLOCK_WIDTH),
                   .RD_PORTS    (2),
                   .WR_PORTS    (1),
                   .RESETABLE   (0))
            sram_data(.clk                  (clk),
                      .rst_n                (rst_n),
                      .read_address         (read_address),
                      .data_out             (read_data[i]),
                      .Wr_En                (write_en_data[i]),
                      .write_address        (write_line_select),
                      .new_data             (new_data));
        end
    end endgenerate
    //Replacement Policy Modules
    generate
        if(ASSOCIATIVITY>1) begin
            lru #(ASSOCIATIVITY,ENTRIES,INDEX_BITS,OUTPUT_BITS)
            lru(.clk            (clk),
                .rst_n          (rst_n),
                .line_selector  (read_line_select),
                .referenced_set (entry_used),
                .lru_update     (lru_update),
                .lru_way        (lru_way));
        end
    endgenerate

    //Assert the Individual Hit Lines for Each Way
    always_comb begin : FindEntry
        entry_used   = 0;
        block_picked = data[0];
        tag_picked   = tag[0];
        for (int i = 0; i < ASSOCIATIVITY; i++) begin
            if((tag[i]==tag_usearch) && validity[i][read_line_select]) begin
                entry_found[i] = 1'd1;
                entry_used     = i;
                block_picked   = data[i];
                tag_picked     = tag[i];
            end else begin
                entry_found[i] = 1'd0;
            end
        end
    end
    assign Hit = |entry_found;
    // Create the second read memory port when vector enabled
    generate if (VECTOR_ENABLED) begin
        assign read_line_select_b  = vct_head_addr_b[OFFSET_BITS+INDEX_BITS-1 : OFFSET_BITS];
        assign tag_usearch_b       = vct_head_addr_b[OFFSET_BITS+INDEX_BITS +: TAG_BITS];
        always_comb begin : FindEntry_B
            block_picked_b = data[0];
            for (int i = 0; i < ASSOCIATIVITY; i++) begin
                if((tag_b[i]==tag_usearch_b) && validity[i][read_line_select_b]) begin
                    entry_found_b[i] = 1'd1;
                    block_picked_b   = data_b[i];
                end else begin
                    entry_found_b[i] = 1'd0;
                end
            end
        end
        assign Hit_b = |entry_found_b;
    end endgenerate

    //Pick the correct Data and Serve
    always_comb begin : DataServe
        if(serve==LD_IN) begin
            if(wt_s_frw_hit) begin
                //Forward from Wait Buffer
                served     = 1'b1;
                must_wait  = 1'b0;
                lru_update = 1'b0;
                served_output.data = wt_s_frw_data;
            end else if(st_s_vhit) begin
                //Forward from Store Buffer
                served     = 1'b1;
                must_wait  = 1'b0;
                lru_update = 1'b0;
                served_output.data = st_s_data;
            end else if(Hit) begin
                //Grab from Cache
                served     = 1'b1;
                must_wait  = 1'b0;
                lru_update = 1'b1;
                served_output.data = served_data;
            end else begin
                //Can not Serve
                served     = 1'b0;
                lru_update = 1'b0;
                served_output.data = served_data;
                if(st_s_phit | ld_s_phit) begin
                //Store in Wait Buffer
                    must_wait = 1'b1;
                end else begin
                //Store in Load Buffer
                    must_wait = 1'b0;
                end
            end
        end else if(serve==ST_IN) begin
            served_output.data = served_data;
            if(update_l2_valid) begin
                //Write Conflict.. Store will wait in Buffers
                served     = 1'b0;
                lru_update = 1'b0;
                if(st_s_phit | ld_s_phit) begin
                    //Store in Wait Buffer
                    must_wait = 1'b1;
                end else begin
                    //Store in Store Buffer
                    must_wait = 1'b0;
                end
            end else begin
                //Serve the Store
                if(st_s_phit) begin
                    //Previous Store was in ST Buffer.. Must wait in Wait Buffer
                    served     = 1'b0;
                    must_wait  = 1'b1;
                    lru_update = 1'b0;
                end else if(Hit) begin
                    //If Hit Serve Normally
                    served     = 1'b1;
                    must_wait  = 1'b0;
                    lru_update = 1'b1;
                end else if(ld_s_phit) begin
                    //If load in LD Buffer, store in Wait Buffer
                    served     = 1'b0;
                    must_wait  = 1'b1;
                    lru_update = 1'b0;
                end else begin
                    //Store in Store Buffer
                    served     = 1'b0;
                    must_wait  = 1'b0;
                    lru_update = 1'b0;
                end
            end
        end else if(serve==LD) begin
            served     = 1'b1;
            must_wait  = 1'b0;
            lru_update = 1'b1;
            served_output.data = served_data;
        end else if(serve==ST) begin
            served     = 1'b1;
            must_wait  = 1'b0;
            lru_update = 1'b1;
            served_output.data = served_data;
        end else if (serve==WT) begin
            served     = 1'b1;
            must_wait  = 1'b0;
            lru_update = 1'b1;
            served_output.data = served_data;
        end else if (serve==VCT_LD) begin
            served     = Hit;
            must_wait  = 1'b0;
            lru_update = Hit;
            served_output.data = served_data;
        end else if (serve==VCT_LD) begin
            served     = Hit;
            must_wait  = 1'b0;
            lru_update = Hit;
            served_output.data = served_data;
        end else begin
            served     = 1'b0;
            must_wait  = 1'b0;
            lru_update = 1'b0;
            served_output.data = served_data;
        end
    end
    //Search for Validities
    always_comb begin : IsAllValid
        //all_valid<='d1;
        for (int i = 0; i < ASSOCIATIVITY; i++) begin
            all_valid_temp[i] = validity[i][write_line_select];
        end
    end
    //Indicates if all entries are valid
    assign all_valid = &all_valid_temp;

    //WRITE Enablers
    generate
        if(ASSOCIATIVITY>1) begin
            always_comb begin : WriteEnablers
                new_valid_entry = 0;
                write_en_data = 'b0;
                write_en_tag  = 'b0;
                if(update_l2_valid) begin
                    write_en_data = 'b0;
                    write_en_tag  = 'b0;
                    //Check if invalid entries exist
                    if(!all_valid) begin
                        for (int i = 0; i < ASSOCIATIVITY; i++) begin
                            if(!validity[i][write_line_select]) begin
                                new_valid_entry = i;
                                write_en_data[i] = 1'b1;
                                write_en_tag[i]  = 1'b1;
                                break;
                            end
                        end
                    end else begin
                        //no invalid entries, evict LRU
                        new_valid_entry = lru_way;
                        write_en_data[lru_way] = 1'b1;
                        write_en_tag[lru_way]  = 1'b1;
                    end
                end else if (serve==ST_IN && served) begin
                    write_en_data[entry_used] = 1'b1;
                    write_en_tag[entry_used]  = 1'b0;
                end else if (serve==ST) begin
                    write_en_data[entry_used] = 1'b1;
                    write_en_tag[entry_used]  = 1'b0;
                end else if(serve==WT && wt_s_isstore) begin
                    write_en_data[entry_used] = 1'b1;
                    write_en_tag[entry_used]  = 1'b0;
                end else begin
                    write_en_data = 'b0;
                    write_en_tag  = 'b0;
                end
            end
        end else if (ASSOCIATIVITY==1) begin
            assign write_en_data = update_l2_valid | (serve==ST_IN && served) | (serve==ST) | (serve==WT && wt_s_isstore);
            assign write_en_tag  = update_l2_valid;
        end
    endgenerate

    //VALIDITY Management
    generate
        if(ASSOCIATIVITY>1) begin
            always_ff @(posedge clk or negedge rst_n) begin : ValidityManagement
                if(!rst_n) begin
                    for (int i = 0; i < ASSOCIATIVITY; i++) begin
                        validity[i] <= 'b0;
                    end
                end else begin
                    if(update_l2_valid) begin
                        if(!all_valid) begin
                            //Store new Data into an invalid Entry
                            validity[new_valid_entry][write_line_select] <= 1'b1;
                        end else begin
                            //Store new Data into the LRU Entry
                            validity[lru_way][write_line_select] <= 1'b1;
                        end
                    end
                end
            end
        end else if (ASSOCIATIVITY==1) begin
            always_ff @(posedge clk or negedge rst_n) begin : ValidityManagement
                if(!rst_n) begin
                    validity <= 0;
                end else begin
                    if(update_l2_valid) begin
                        //Store new Data into the Entry
                        validity[write_line_select] <= 1'b1;
                    end
                end
            end
        end
    endgenerate

    //DIRTY Management
    generate
        if(ASSOCIATIVITY>1) begin
            always_ff @(posedge clk or negedge rst_n) begin : DirtyManagement
                if(!rst_n) begin
                    for (int i = 0; i < ASSOCIATIVITY; i++) begin
                        dirty[i] <= 'b0;
                    end
                end else begin
                    if(update_l2_valid) begin
                        if(!all_valid) begin
                            //Store new Data into an invalid Entry
                            dirty[new_valid_entry][write_line_select] <= 1'b0;
                        end else begin
                            //Store new Data into the LRU Entry
                            dirty[lru_way][write_line_select] <= 1'b0;
                        end
                    end else if(serve==ST_IN && served) begin
                        dirty[entry_used][write_line_select] <= 1'b1;
                    end else if(serve==ST) begin
                        dirty[entry_used][write_line_select] <= 1'b1;
                    end else if(serve==WT && wt_s_isstore) begin
                        dirty[entry_used][write_line_select] <= 1'b1;
                    end
                end
            end
        end else if (ASSOCIATIVITY==1) begin
            always_ff @(posedge clk or negedge rst_n) begin : DirtyManagement
                if(!rst_n) begin
                    dirty <= 'b0;
                end else begin
                    if(update_l2_valid) begin
                        dirty[write_line_select] <= 1'b0;
                    end else if(serve==ST_IN && served) begin
                        dirty[write_line_select] <= 1'b1;
                    end else if(serve==ST) begin
                        dirty[write_line_select] <= 1'b1;
                    end else if(serve==WT && wt_s_isstore) begin
                        dirty[write_line_select] <= 1'b1;
                    end
                end
            end
        end
    endgenerate

    //Create the cache is_blocked Output
    assign cache_blocked = ~ld_ready | ~st_ready | ~wt_ready | wt_in_walk;

    //Pick what will be served (comb FSM) && Pick the address to be served this cycle
    always_comb begin : ServePriority
        if(wt_in_walk) begin
            serve = WT;
            served_address = search_address_o;
            served_microop = wt_s_microop;
        end else if(load_valid && !output_used) begin
            serve = LD_IN;
            served_address = load_address;
            served_microop = load_microop;
        end else if(store_valid && !output_used) begin
            serve = ST_IN;
            served_address = store_address;
            served_microop = store_microop;
        end else if(ld_valid && ld_head_isfetched && !output_used) begin
            serve = LD;
            served_address = ld_head_addr;
            served_microop = ld_head_microop;
        end else if(st_valid && st_head_isfetched && !output_used && !update_l2_valid) begin
            serve = ST;
            served_address = st_head_addr;
            served_microop = st_head_microop;
        end else if (vct_valid && !vct_head_isstore) begin
            serve = VCT_LD;
            served_address = vct_head_addr;
            served_microop = vct_head_microop;
        end else if (vct_valid && vct_head_isstore && !update_l2_valid) begin
            serve = VCT_ST;
            served_address = vct_head_addr;
            served_microop = vct_head_microop;
        end else begin
            serve = IDLE;
            served_address = update_l2_addr;
            served_microop = load_microop;
        end
    end

    // New tag on Hit stores is the same as the old one
    assign new_modded_tag = tag_picked;

    always_comb begin : DataPicked
        if(serve==ST_IN) begin
            data_picked = store_data;
        end else if(serve==ST) begin
            data_picked = st_head_data;
        end else begin
            data_picked = wt_s_data;
        end
    end
    //Initialize the Operations Module
    data_operation #(
        .ADDR_W     (OFFSET_BITS),
        .DATA_W     (DATA_WIDTH),
        .MICROOP    (MICROOP),
        .BLOCK_W    (BLOCK_WIDTH),
        .LOAD_ONLY  (0)
        )
    data_operation  (
        .input_address  (offset_select),
        .input_block    (block_picked),
        .input_data     (data_picked),
        .microop        (served_microop),

        .valid_exc      (served_exc_v),
        .exception      (served_exc),
        .output_block   (scalar_new_modded_block),
        .output_vector  (served_data)
        );

    assign ld_pop  = (serve==LD);
    assign ld_push = (serve==LD_IN) & ~served & ~must_wait & ~ld_s_phit;
    //Initialize the Load Buffer
    ld_st_buffer #(
        .DATA_WIDTH     (DATA_WIDTH),
        .ADDR_BITS      (ADDR_BITS),
        .BLOCK_ID_START (OFFSET_BITS),
        .R_WIDTH        (R_WIDTH),
        .MICROOP        (MICROOP),
        .ROB_TICKET     (ROB_TICKET),
        .DEPTH          (BUFFER_SIZES))
    load_buffer (
        .clk                (clk),
        .rst_n              (rst_n),

        .push               (ld_push),
        .write_address      (load_address),
        .write_data         (),             //NC
        .write_microop      (load_microop),
        .write_dest         (load_dest),
        .write_ticket       (load_ticket),
        .write_isfetched    (1'b0),

        .search_address     (served_address),
        .search_microop_in  (),             //NC
        .search_data        (),             //NC
        .search_microop     (),             //NC
        .search_dest        (),             //NC
        .search_ticket      (),             //NC
        .search_valid_hit   (),             //NC
        .search_partial_hit (ld_s_phit),

        .valid_update       (update_l2_valid),
        .update_address     (update_l2_addr),

        .pop                (ld_pop),
        .head_isfetched     (ld_head_isfetched),
        .head_address       (ld_head_addr),
        .head_data          (),             //NC
        .head_microop       (ld_head_microop),
        .head_dest          (ld_head_dest),
        .head_ticket        (ld_head_ticket),

        .valid              (ld_valid),
        .ready              (ld_ready)
        );


    assign st_pop  = (serve==ST);
    assign st_push = (serve==ST_IN & ~served & ~must_wait & ~st_s_phit);
    //Initialize the Store Buffer
    ld_st_buffer #(
        .DATA_WIDTH     (DATA_WIDTH),
        .ADDR_BITS      (ADDR_BITS),
        .BLOCK_ID_START (OFFSET_BITS),
        .R_WIDTH        (R_WIDTH),
        .MICROOP        (MICROOP),
        .ROB_TICKET     (ROB_TICKET),
        .DEPTH          (BUFFER_SIZES))
    store_buffer (
        .clk                (clk),
        .rst_n              (rst_n),

        .push               (st_push),
        .write_address      (store_address),
        .write_data         (store_data),
        .write_microop      (store_microop),
        .write_dest         (),             //NC
        .write_ticket       (),             //NC
        .write_isfetched    (Hit),

        .search_address     (served_address),
        .search_microop_in  (served_microop),
        .search_data        (st_s_data),
        .search_microop     (),             //NC
        .search_dest        (),             //NC
        .search_ticket      (),             //NC
        .search_valid_hit   (st_s_vhit),
        .search_partial_hit (st_s_phit),

        .valid_update       (update_l2_valid),
        .update_address     (update_l2_addr),

        .pop                (st_pop),
        .head_isfetched     (st_head_isfetched),
        .head_address       (st_head_addr),
        .head_data          (st_head_data),
        .head_microop       (st_head_microop),
        .head_dest          (),             //NC
        .head_ticket        (),             //NC

        .valid              (st_valid),
        .ready              (st_ready)
        );

    //Enter in WT Buffer Serve Mode
    assign wt_invalidate = (serve==LD | serve==ST) & wt_found_one;
    //Save the Search Address
    always_ff @(posedge clk) begin : SavedSearch
        if(serve==LD && wt_found_one) begin
                saved_search_addr <= ld_head_addr;
        end else if(serve==ST && wt_found_one) begin
            saved_search_addr <= st_head_addr;
        end
    end

    always_comb begin : WaitBufferInputs
        wt_w_dest   = load_dest;
        wt_w_ticket = load_ticket;
        wt_w_data   = store_data;
        if(serve==LD_IN) begin
            wt_w_address = load_address;
            wt_w_microop = load_microop;
        end else begin
            wt_w_address = store_address;
            wt_w_microop = store_microop;
        end
    end

    assign wt_w_isstore   = (serve==ST_IN);
    assign wt_push        = (serve==LD_IN & ~served & must_wait) | (serve==ST_IN & ~served & must_wait);
    assign wt_search_addr = (serve==WT) ? saved_search_addr: served_address;
    //Initialize the Wait Buffer
    wait_buffer #(
        .DATA_WIDTH         (DATA_WIDTH),
        .ADDR_BITS          (ADDR_BITS),
        .R_WIDTH            (R_WIDTH),
        .MICROOP            (MICROOP),
        .ROB_TICKET         (ROB_TICKET),
        .DEPTH              (2*BUFFER_SIZES)
        )
    wait_buffer  (
        .clk                (clk),
        .rst_n              (rst_n),

        .write_enable       (wt_push),
        .write_is_store     (wt_w_isstore),
        .write_address      (wt_w_address),
        .write_data         (wt_w_data),
        .write_microop      (wt_w_microop),
        .write_dest         (wt_w_dest),
        .write_ticket       (wt_w_ticket),

        .search_invalidate  (wt_invalidate),
        .search_address     (wt_search_addr),
        .search_microop_in  (served_microop),
        .search_address_o   (search_address_o),
        .search_is_store    (wt_s_isstore),
        .search_data        (wt_s_data),
        .search_frw_data    (wt_s_frw_data),
        .search_microop     (wt_s_microop),
        .search_dest        (wt_s_dest),
        .search_ticket      (wt_s_ticket),
        .search_valid_hit   (wt_s_frw_hit),

        .valid              (wt_valid),
        .ready              (wt_ready),
        .search_found_one   (wt_found_one),
        .search_found_multi (),             //NC
        .in_walk_mode       (wt_in_walk)
        );

    generate if(VECTOR_ENABLED) begin: g_vector_buffer
        localparam SIZE_WIDTH = $clog2(VECTOR_REQ_WIDTH/8)+1;

        logic [  VECTOR_REQ_WIDTH-1:0] vct_head_data              ;
        logic [        SIZE_WIDTH-1:0] vct_head_size              ;
        logic [        INDEX_BITS-1:0] line_select_a              ;
        logic [        INDEX_BITS-1:0] line_select_b              ;
        logic [     2*BLOCK_WIDTH-1:0] block_picked_double        ;
        logic [     2*BLOCK_WIDTH-1:0] vct_new_modded_block_double;
        logic [$clog2(VECTOR_LANES):0] vct_head_ticket            ;
        logic                          nxt_multi_fetches_needed   ;
        logic                          multi_fetches_needed       ;
        logic                          multi_fetches_en           ;
        logic                          vct_push                   ;
        logic                          vct_pop                    ;

        assign Hit_a    = Hit;
        assign vct_push = mem_req_valid_i & cache_vector_ready_o;
        assign vct_pop  = (multi_fetches_needed | nxt_multi_fetches_needed) ? (serve===VCT_ST | serve===VCT_LD) & Hit_a & Hit_b :
                                                                              (serve===VCT_ST | serve===VCT_LD) & Hit_a;
        //Calculate if the data span in two cache lines
        assign vct_head_addr_b          = vct_head_addr + vct_head_size -1;
        assign line_select_a            = vct_head_addr[OFFSET_BITS+INDEX_BITS-1 : OFFSET_BITS];
        assign line_select_b            = vct_head_addr_b[OFFSET_BITS+INDEX_BITS-1 : OFFSET_BITS];
        assign nxt_multi_fetches_needed = (line_select_a !== line_select_b); //check if the last byte of the transfer is in a different cache line

        assign multi_fetches_en = ~multi_fetches_needed & (serve===VCT_ST | serve===VCT_LD);
        always_ff @(posedge clk or negedge rst_n) begin : proc_multi_fetch_FSM
            if(~rst_n) begin
                multi_fetches_needed <= 1'b0;
            end else if (multi_fetches_en) begin
                multi_fetches_needed <= nxt_multi_fetches_needed;
            end else if (multi_fetches_needed & vct_pop) begin
                multi_fetches_needed <= 1'b0;
            end
        end
        // Maintain the FSM tracking multi-line fetches
        assign vct_request_a = (serve===VCT_ST | serve===VCT_LD) & ~Hit_a & ~vct_head_requested[0];
        assign vct_request_b = (serve===VCT_ST | serve===VCT_LD) & (vct_head_requested[0] | Hit_a) & ~vct_head_requested[1] & (multi_fetches_needed | nxt_multi_fetches_needed);
        always_ff @(posedge clk or negedge rst_n) begin : proc_head_requested
            if(~rst_n) begin
                vct_head_requested <= '0;
            end else begin
                if(vct_pop) begin
                    vct_head_requested <= '0;
                end else if(vct_request_a) begin
                    vct_head_requested[0] <= 1'b1;
                end else if(vct_request_b) begin
                    vct_head_requested <= 2'b11;
                end
            end
        end
        vld_st_buffer #(
            .DATA_WIDTH    (VECTOR_REQ_WIDTH      ),
            .ADDR_BITS     (ADDR_BITS             ),
            .BLOCK_ID_START(OFFSET_BITS           ),
            .MICROOP_WIDTH (VECTOR_MICROOP_WIDTH  ),
            .TICKET_WIDTH  ($clog2(VECTOR_LANES)+1),
            .SIZE_WIDTH    (SIZE_WIDTH            ),
            .DEPTH         (4                     )
        ) vld_st_buffer (
            .clk             (clk                 ),
            .rst_n           (rst_n               ),

            .push            (vct_push            ),
            .write_address   (mem_req_i.address   ),
            .write_data      (mem_req_i.data      ),
            .write_ticket    (mem_req_i.ticket    ),
            .write_size      (mem_req_i.size      ),
            .write_microop   (mem_req_i.microop   ),

            .valid_update_i  (update_l2_valid     ),
            .update_address_i(update_l2_addr      ),

            .valid_o         (vct_valid           ),
            .ready_o         (cache_vector_ready_o),
            .pop             (vct_pop             ),
            .head_is_store   (vct_head_isstore    ),
            .head_is_fetched (                    ),
            .head_address    (vct_head_addr       ),
            .head_data       (vct_head_data       ),
            .head_microop    (vct_head_microop    ),
            .head_ticket     (vct_head_ticket     ),
            .head_size       (vct_head_size       )
        );

        assign block_picked_double = {block_picked_b,block_picked};
        vdata_operation #(
            .ADDR_W   (OFFSET_BITS         ),
            .DATA_W   (VECTOR_REQ_WIDTH    ),
            .MICROOP_W(VECTOR_MICROOP_WIDTH),
            .SIZE_W   (SIZE_WIDTH          ),
            .BLOCK_W  (BLOCK_WIDTH         )
        ) vdata_operation (
            .clk          (clk                        ),
            .valid_i      (vct_pop                    ),
            //Inputs
            .input_address(offset_select              ),
            .input_block  (block_picked_double        ),
            .input_data   (vct_head_data              ),
            .microop      (vct_head_microop           ),
            .size         (vct_head_size              ),
            //Outputs
            .valid_exc    (                           ),
            .exception    (                           ),
            .output_block (vct_new_modded_block_double),
            .output_vector(vct_served_data            )
        );
        assign vct_new_modded_block = vct_new_modded_block_double[BLOCK_WIDTH-1:0];
        assign new_modded_block     = (serve === VCT_LD) | (serve === VCT_ST) ? vct_new_modded_block : scalar_new_modded_block;
        assign vector_resp_valid_o  = (multi_fetches_needed | nxt_multi_fetches_needed) ? serve===VCT_LD & Hit_a & Hit_b :
                                                                                          serve===VCT_LD & Hit_a;
        assign vector_resp.ticket   = vct_head_ticket;
        assign vector_resp.size     = vct_head_size;
        assign vector_resp.data     = vct_served_data;

        // Assertion for WIP features
        assert property (@(posedge clk) disable iff(!rst_n | !VECTOR_ENABLED) (serve === VCT_ST) |-> !nxt_multi_fetches_needed) else $warning("WARNING:Data_Cache: Multi-line stores not yet implemented in the Data Cache");
    end else begin: g_stubs
        assign new_modded_block    = scalar_new_modded_block;
        assign vct_valid           = 1'b0;
        assign vct_head_isstore    = 1'b0;
        assign vector_resp_valid_o = 1'b0;
        assign vct_request_a       = 1'b0;
        assign vct_request_b       = 1'b0;
        assign vct_head_requested  = 2'b00;
    end endgenerate

assert property (@(posedge clk) disable iff(!rst_n) load_valid |-> !store_valid) else $error("ERROR:Data_Cache: Two operations in the same cycle");
assert property (@(posedge clk) disable iff(!rst_n) store_valid |-> !load_valid) else $error("ERROR:Data_Cache: Two operations in the same cycle");
assert property (@(posedge clk) disable iff(!rst_n | !VECTOR_ENABLED) (store_valid | load_valid) |-> (!vct_valid && !mem_req_valid_i)) else $error("ERROR:Data_Cache: Cannot issue scalar mem ops while vector mem op in flight");


endmodule

/*
 * @info Load/Store Buffer Module
 * @info Top Modules: data_cache.sv
 *
 * @author VLSI Lab, EE dept., Democritus University of Thrace
 *
 * @brief  Used in the non-blocking Data Cache.
 *
 * @param DATA_WIDTH    : # of Data Bits (default 32 bits)
 * @param ADDR_BITS     : # of Address Bits (default 32 bits)
 * @param BLOCK_ID_START: # of Bit from which the Block ID starts
 * @param R_WIDTH       : # of Register Bits (default 6 bits)
 * @param MICROOP       : # of Microoperation Bits (default 5 bits)
 * @param ROB_TICKET    : # of ROB Ticket Bits (default 3 bits)
 * @param DEPTH         : # of Entries in Buffer (default 8 entries)
 */
module ld_st_buffer #(
    parameter DATA_WIDTH     = 32,
    parameter ADDR_BITS      = 32,
    parameter BLOCK_ID_START = 5 ,
    parameter R_WIDTH        = 6 ,
    parameter MICROOP        = 5 ,
    parameter ROB_TICKET     = 3 ,
    parameter DEPTH          = 4
) (
    input  logic                  clk               ,
    input  logic                  rst_n             ,
    //Write Port
    input  logic                  push              ,
    input  logic [ ADDR_BITS-1:0] write_address     ,
    input  logic [DATA_WIDTH-1:0] write_data        ,
    input  logic [   MICROOP-1:0] write_microop     ,
    input  logic [   R_WIDTH-1:0] write_dest        ,
    input  logic [ROB_TICKET-1:0] write_ticket      ,
    input  logic                  write_isfetched   ,
    //Search Port & Forward
    input  logic [ ADDR_BITS-1:0] search_address    ,
    input  logic [   MICROOP-1:0] search_microop_in ,
    output logic [DATA_WIDTH-1:0] search_data       ,
    output logic [   MICROOP-1:0] search_microop    ,
    output logic [   R_WIDTH-1:0] search_dest       ,
    output logic [ROB_TICKET-1:0] search_ticket     ,
    output logic                  search_valid_hit  ,
    output logic                  search_partial_hit,
    //Update Port
    input  logic                  valid_update      ,
    input  logic [ ADDR_BITS-1:0] update_address    ,
    //Head Output
    input  logic                  pop               ,
    output logic                  head_isfetched    ,
    output logic [ ADDR_BITS-1:0] head_address      ,
    output logic [DATA_WIDTH-1:0] head_data         ,
    output logic [   MICROOP-1:0] head_microop      ,
    output logic [   R_WIDTH-1:0] head_dest         ,
    output logic [ROB_TICKET-1:0] head_ticket       ,
    //Status Port
    output logic                  valid             ,
    output logic                  ready
);

    localparam INFO_WIDTH = R_WIDTH + MICROOP;
	// #Memory Arrays#
    logic [DEPTH-1:0][ADDR_BITS-1:0]  saved_address;
    logic [DEPTH-1:0][DATA_WIDTH-1:0] saved_data;
    logic [DEPTH-1:0][ROB_TICKET-1:0] saved_ticket;
    logic [DEPTH-1:0][INFO_WIDTH-1:0] saved_info;
    logic [INFO_WIDTH-1:0]            head_info, search_info;
    logic [DEPTH-1:0]                 saved_valid, saved_isfetched;


    // #Internal Signals#
    logic [    DEPTH-1:0] head, tail, stat_counter ;
    logic [    DEPTH-1:0] matched_update, matched_search_main, matched_search_sec, matched_search;
    logic                 will_update, one_found, microop_ok;

    localparam int LD_BF_SIZE = $bits(saved_address) + $bits(saved_ticket) + $bits(saved_info);
    localparam int ST_BF_SIZE = $bits(saved_address) + $bits(saved_data) + $bits(saved_ticket) + $bits(saved_info);

    assign valid = ~stat_counter[0];
    assign ready = ~stat_counter[DEPTH-1];


    //Create the Search Match Vectors
    always_comb begin : MatchSearch
        for (int i = 0; i < DEPTH; i++) begin
            matched_search_main[i] = saved_valid[i] ? (search_address[ADDR_BITS-1:BLOCK_ID_START]==saved_address[i][ADDR_BITS-1:BLOCK_ID_START]) : 1'b0;
            matched_search_sec[i] = saved_valid[i] ? (search_address[BLOCK_ID_START-1:0]==saved_address[i][BLOCK_ID_START-1:0]) : 1'b0;
        end
        for (int i = 0; i < DEPTH; i++) begin
            matched_search[i] = matched_search_main[i] & matched_search_sec[i];// & microop_ok;
        end
    end
    //Check the Microops for forwarding hazards
    always_comb begin : MicroopOk
        if(search_microop_in==5'b00001) begin
            //load==LW
            microop_ok = (search_microop == 5'b00110);
        end else if(search_microop_in==5'b00010 | search_microop_in==5'b00011) begin
            //load==LH
            microop_ok = (search_microop == 5'b00111 | search_microop == 5'b00110);
        end else if(search_microop_in==5'b00100 | search_microop_in==5'b00101) begin
            //load==LB
            microop_ok = 1;
        end else begin
            microop_ok = 0;
        end
    end
    // assign search_valid_hit = |matched_search;
    always_comb begin : ValidHit
        search_valid_hit = 0;
        for (int i = 0; i < DEPTH; i++) begin
            if(matched_search[i] && microop_ok) begin
                search_valid_hit = 1;
            end
        end
    end
    assign search_partial_hit = |matched_search_main;
    //Search the Locations to update as Fetched
    always_comb begin : matchUpdate
        for (int i = 0; i < DEPTH; i++) begin
            matched_update[i] = saved_valid[i] ? (update_address[ADDR_BITS-1:BLOCK_ID_START]==saved_address[i][ADDR_BITS-1:BLOCK_ID_START]) : 1'b0;
        end
    end
    assign will_update = |matched_update & valid_update;
    //Tail Management (moves on new pops)
    always_ff @(posedge clk or negedge rst_n) begin : TailManagement
        if(!rst_n) begin
            tail <= 1;
        end else begin
            if (push) tail <= {tail[DEPTH-2:0], tail[DEPTH-1]};
        end
    end
    // Head Management (moves when it points to an invalid entry)
    always_ff @(posedge clk or negedge rst_n) begin : HeadManagement
        if(!rst_n) begin
            head <= 1;
        end else begin
            if (pop) begin
                head <= {head[DEPTH-2:0], head[DEPTH-1]};
            end
        end
    end
    //Status Counter Management
    always_ff @(posedge clk or negedge rst_n) begin : statCounter
        if(!rst_n) begin
            stat_counter <= 1;
        end else begin
            if (push & !pop) begin
                // shift left status counter (increment)
                stat_counter <= stat_counter << 1;
            end else if (!push &  pop) begin
                // shift right status counter (decrement)
                stat_counter <= stat_counter >> 1;
            end
        end
    end
    // Memory Management (Data Write)
    always_ff @(posedge clk) begin : MemoryData
        for (int i = 0; i < DEPTH; i++) begin
            if(push && tail[i]) begin
                saved_address[i] <= write_address;
                saved_data[i]    <= write_data;
                saved_ticket[i]  <= write_ticket;
                saved_info[i]    <= {write_dest,write_microop};
            end
        end
    end
    // Memory Management (Validity)
    always_ff @(posedge clk or negedge rst_n) begin : MemoryValidity
        if(!rst_n) begin
            saved_valid <= 'b0;
        end else begin
            for (int i = 0; i < DEPTH; i++) begin
                if(push && tail[i]) begin
                    saved_valid[i]   <= 1'b1;
                end else if(pop && head[i]) begin
                    saved_valid[i]   <= 1'b0;
                end
            end
        end
    end
    // Memory Management (is_fetched)
    always_ff @(posedge clk or negedge rst_n) begin : MemoryFetched
        if(!rst_n) begin
            saved_isfetched <= 'b0;
        end else begin
            for (int i = 0; i < DEPTH; i++) begin
                if(push && tail[i]) begin
                    saved_isfetched[i] <= write_isfetched;
                end else if(will_update && matched_update[i]) begin
                    saved_isfetched[i] <= 1'b1;
                end
            end
        end
    end

    //HEAD OUTPUTS
    // Pick the Address Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (ADDR_BITS)
    ) mux_addr (
        .data_in (saved_address ),
        .sel     (head       ),
        .data_out(head_address)
    );
    // Pick the Data Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (DATA_WIDTH)
    ) mux_data (
        .data_in (saved_data ),
        .sel     (head       ),
        .data_out(head_data)
    );

    //Pick the Microop/Destination Output
    and_or_mux #(
        .INPUTS    (DEPTH  ),
        .DW        (INFO_WIDTH)
    ) mux_info (
        .data_in (saved_info ),
        .sel     (head       ),
        .data_out(head_info)
    );
    assign head_microop = head_info[0 +: MICROOP];
    assign head_dest    = head_info[MICROOP +: R_WIDTH];
    //Pick the Ticket Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (ROB_TICKET)
    ) mux_ticket (
        .data_in (saved_ticket ),
        .sel     (head         ),
        .data_out(head_ticket)
    );
    //Pick the is_fetched Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (1)
    ) mux_is_fetched (
        .data_in (saved_isfetched ),
        .sel     (head         ),
        .data_out(head_isfetched)
    );


    //SEARCH OUTPUTS
    // Pick the Data Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (DATA_WIDTH)
    ) mux_data_s (
        .data_in (saved_data ),
        .sel     (matched_search),
        .data_out(search_data)
    );
    //Pick the Microop/Destination Output
    and_or_mux #(
        .INPUTS    (DEPTH  ),
        .DW        (INFO_WIDTH)
    ) mux_info_s (
        .data_in (saved_info ),
        .sel     (matched_search),
        .data_out(search_info)
    );
    assign search_microop = search_info[0 +: MICROOP];
    assign search_dest    = search_info[MICROOP +: R_WIDTH];
    //Pick the Ticket Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (ROB_TICKET)
    ) mux_ticket_s (
        .data_in (saved_ticket ),
        .sel     (matched_search),
        .data_out(search_ticket)
    );

    assert property (@(posedge clk) disable iff(!rst_n) push |-> ready) else $error("ERROR:LD_ST Buffer: Push on Full");
    assert property (@(posedge clk) disable iff(!rst_n) pop |-> valid) else $error("ERROR:LD_ST Buffer: Pop on Empty");

endmodule

/*
 * @info Wait Buffer Module
 * @info Top Modules: data_cache.sv
 *
 * @author VLSI Lab, EE dept., Democritus University of Thrace
 *
 * @brief  Used in the non-blocking Data Cache.
 *
 * @param DATA_WIDTH    : # of Data Bits (default 32 bits)
 * @param ADDR_BITS     : # of Address Bits (default 32 bits)
 * @param BLOCK_ID_START: # of Bit from which the Block ID starts
 * @param R_WIDTH       : # of Register Bits (default 6 bits)
 * @param MICROOP       : # of Microoperation Bits (default 5 bits)
 * @param ROB_TICKET    : # of ROB Ticket Bits (default 3 bits)
 * @param DEPTH         : # of Entries in Buffer (default 8 entries)
 */
module wait_buffer #(
    parameter DATA_WIDTH     = 32,
    parameter ADDR_BITS      = 32,
    parameter BLOCK_ID_START = 5 ,
    parameter R_WIDTH        = 6 ,
    parameter MICROOP        = 5 ,
    parameter ROB_TICKET     = 3 ,
    parameter DEPTH          = 8  )
    //Interfaces
    (input logic                  clk,
    input  logic                  rst_n,
    //Write Port
    input  logic                  write_enable,
    input  logic                  write_is_store,
    input  logic[ADDR_BITS-1:0]   write_address,
    input  logic[DATA_WIDTH-1:0]  write_data,
    input  logic[MICROOP-1 : 0]   write_microop,
    input  logic[R_WIDTH-1 : 0]   write_dest,
    input  logic[ROB_TICKET-1 : 0]write_ticket,
    //Search Port
    input  logic                  search_invalidate,
    output logic                  search_is_store,
    input  logic[ADDR_BITS-1:0]   search_address,
    input  logic[MICROOP-1 : 0]   search_microop_in,
    output logic[ADDR_BITS-1:0]   search_address_o,
    output logic[DATA_WIDTH-1:0]  search_data,
    output logic[DATA_WIDTH-1:0]  search_frw_data,
    output logic[MICROOP-1 : 0]   search_microop,
    output logic[R_WIDTH-1 : 0]   search_dest,
    output logic[ROB_TICKET-1 : 0]search_ticket,
    output logic                  search_valid_hit,
    //Status Port
    output logic                  valid,
    output logic                  ready,
    output logic                  search_found_one,
    output logic                  search_found_multi,
    output logic                  in_walk_mode
);
    localparam INFO_WIDTH = MICROOP + R_WIDTH + ROB_TICKET;
    // #Memory Arrays#
    logic [DEPTH-1:0][ADDR_BITS-1:0]  saved_address;
    logic [DEPTH-1:0][DATA_WIDTH-1:0] saved_data;
    logic [DEPTH-1:0][INFO_WIDTH-1:0] saved_info;
    logic [INFO_WIDTH-1:0]            search_info;
    logic [DEPTH-1:0]                 saved_is_store, saved_valid;

    // #Internal Signals#
    logic [    DEPTH-1:0] head, tail, peek, tail_reversed, stat_counter, arb_priority ;
    logic [    DEPTH-1:0] matched_search_main, matched_search_sec, matched, match_picked, forward_matched;
    logic                 pop, one_found, multi_found, microop_ok;

    localparam int WT_BF_SIZE = $bits(saved_info) + $bits(saved_data) + $bits(saved_address);
    //FSM Type
    typedef enum logic {IDLE, WALK} buffer_mode;
    buffer_mode mode;

    assign valid = ~stat_counter[0];
    assign ready = ~stat_counter[DEPTH-1];
    assign in_walk_mode = (mode==WALK);

    // Search in the Array
    always_comb begin : Search
        for (int i = 0; i < DEPTH; i++) begin
            matched_search_main[i] = saved_valid[i] ? (search_address[ADDR_BITS-1:BLOCK_ID_START]==saved_address[i][ADDR_BITS-1:BLOCK_ID_START]) : 1'b0;
            matched_search_sec[i]  = saved_valid[i] ? (search_address[BLOCK_ID_START-1:0]==saved_address[i][BLOCK_ID_START-1:0]) : 1'b0;
            // matched[i]  = saved_valid[i] ? (search_address[31:2] == saved_address[i][31:2]) : 1'b0;
            matched[i]  = matched_search_main[i] & matched_search_sec[i] & microop_ok;
        end
    end
    assign search_valid_hit = |matched;
    //Check the Microops for forwarding hazards
    always_comb begin : MicroopOk
        if(search_microop_in==5'b00001) begin
            //load==LW
            microop_ok = (search_microop == 5'b00110);
        end else if(search_microop_in==5'b00010 | search_microop_in==5'b00011) begin
            //load==LH
            microop_ok = (search_microop == 5'b00111 | search_microop == 5'b00110);
        end else if(search_microop_in==5'b00100 | search_microop_in==5'b00101) begin
            //load==LB
            microop_ok = 1;
        end else begin
            microop_ok = 0;
        end
    end
    assign arb_priority = (mode==IDLE) ? head : {peek[DEPTH-2:0], peek[DEPTH-1]};
    //Initialize the Arbiter (oldest entry->newest entry)
    arbiter #(DEPTH)
    arbiter(
        .request_i      (matched_search_main), //instead of matched
        .priority_i     (arb_priority),
        .grant_o        (match_picked),
        .anygnt_o       (one_found)
        );
    //Initialize the One-Hot Detector
    onehot_detect #(DEPTH)
    onehot_detect  (
        .vec_in         (matched_search_main), //- matched <> matched_search_main
        .exactly_one    (),
        .more_than_one  (multi_found)
        );

    // Peek Pointer Management
    always_ff @(posedge clk or negedge rst_n) begin : PeekManagement
        if(!rst_n) begin
            peek <= 1;
        end else begin
            if(mode==IDLE && search_invalidate) begin
                peek <= match_picked;
            end else if(mode==IDLE && pop) begin
                peek <= peek << 1;
            end else if(mode==WALK && !multi_found) begin
                peek <= head;
            end else if(mode==WALK) begin
                peek <= match_picked;
            end else begin
                peek <= head;
            end
        end
    end
    //FSM Management
    always_ff @(posedge clk or negedge rst_n) begin : proc_
        if(~rst_n) begin
            mode <= IDLE;
        end else begin
            unique case (mode)
                IDLE: if(search_invalidate) begin
                          mode <= WALK;
                      end else begin
                          mode <= IDLE;
                      end
                WALK: if(!multi_found) begin
                          mode <= IDLE;
                      end else begin
                          mode <= WALK;
                      end
            endcase
        end
    end
    // Create the Rest of the Outputs
    assign search_found_multi = multi_found;
    assign search_found_one   = one_found;

    // Create the Pop Command
    always_comb begin : PopCommand
        pop = 0;
        for (int i = 0; i < DEPTH; i++) begin
            if (head[i] && !saved_valid[i]) begin
                pop = valid;
            end
        end
    end
    //Tail Management (moves on new pops)
    always_ff @(posedge clk or negedge rst_n) begin : TailManagement
        if(!rst_n) begin
            tail <= 1;
        end else begin
            if (write_enable) tail <= {tail[DEPTH-2:0], tail[DEPTH-1]};
        end
    end
    // Head Management (moves when it points to an invalid entry)
    always_ff @(posedge clk or negedge rst_n) begin : HeadManagement
        if(!rst_n) begin
            head <= 1;
        end else begin
            if (pop) begin
                head <= {head[DEPTH-2:0], head[DEPTH-1]};
            end
        end
    end
    //Status Counter Management
    always_ff @(posedge clk or negedge rst_n) begin : statCounter
        if(!rst_n) begin
            stat_counter <= 1;
        end else begin
            if (write_enable & !pop) begin
                // shift left status counter (increment)
                stat_counter <= stat_counter << 1;
            end else if (!write_enable &  pop) begin
                // shift right status counter (decrement)
                stat_counter <= stat_counter >> 1;
            end
        end
    end
    // Memory Management (Data Write)
    always_ff @(posedge clk) begin : Memory
        for (int i = 0; i < DEPTH; i++) begin
            if(write_enable && tail[i]) begin
                saved_is_store[i] <= write_is_store;
                saved_address[i]  <= write_address;
                saved_data[i]     <= write_data;
                saved_info[i]     <= {write_microop,write_dest,write_ticket};
            end
        end
    end
    // Memory Management (Validity)
    always_ff @(posedge clk or negedge rst_n) begin : Memory_Validity
        if(!rst_n) begin
            saved_valid <= 'b0;
        end else begin
            for (int i = 0; i < DEPTH; i++) begin
                if(write_enable && tail[i]) begin
                    saved_valid[i] <= 1'b1;
                end else if(mode==WALK && peek[i]) begin
                    saved_valid[i] <= 1'b0;
                end
            end
        end
    end
    logic [    DEPTH-1:0] matched_reversed,final_frw_matched,forward_matched_r;
    always_comb begin : InvertPointers
        for (int i = 0; i < DEPTH; i++) begin
            tail_reversed[i] = tail[DEPTH-1-i];
            matched_reversed[i] = matched[DEPTH-1-i];
            final_frw_matched[i]  = forward_matched_r[DEPTH-1-i];
        end

    end
    //FORWARDED OUTPUTS
    //Forwarded
     // Data Arbiter (newest entry -> oldest entry)
    arbiter #(DEPTH)
    frw_arbiter(
        .request_i      (matched_reversed),
        .priority_i     (tail_reversed),
        .grant_o        (forward_matched_r),
        .anygnt_o       ()
        );
    // Pick the Forwarded Data Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (DATA_WIDTH)
    ) mux_frw_data (
        .data_in (saved_data ),
        .sel     (final_frw_matched),
        .data_out(search_frw_data)
    );

    //SEARCH OUTPUTS (+Walk Mode Outputs)
    // Pick the Address Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (ADDR_BITS)
    ) mux_addr (
        .data_in (saved_address ),
        .sel     (peek       ),
        .data_out(search_address_o)
    );
    // Pick the Data Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (DATA_WIDTH)
    ) mux_data (
        .data_in (saved_data ),
        .sel     (peek       ),
        .data_out(search_data)
    );

    //Pick the is_store Output
    and_or_mux #(
        .INPUTS    (DEPTH),
        .DW        (1    )
    ) mux_is_store (
        .data_in (saved_is_store ),
        .sel     (peek           ),
        .data_out(search_is_store)
    );
    //Pick the Ticket/Microoperation/Destination Output
    and_or_mux #(
        .INPUTS    (DEPTH     ),
        .DW        (INFO_WIDTH)
    ) mux_info (
        .data_in (saved_info ),
        .sel     (peek         ),
        .data_out(search_info)
    );
    assign search_ticket  = search_info[0 +: ROB_TICKET];
    assign search_dest    = search_info[ROB_TICKET +: R_WIDTH];
    assign search_microop = search_info[ROB_TICKET+R_WIDTH +: MICROOP];

    //Pick the valid match bit
    // and_or_mux #(
    //     .INPUTS    (DEPTH),
    //     .DW        (1    )
    // ) mux_valid (
    //     .data_in (matched ),
    //     .sel     (peek           ),
    //     .data_out(search_valid_hit)
    // );

    assert property (@(posedge clk) disable iff(!rst_n) write_enable |-> ready) else $error("ERROR:WT Buffer: Push on Full");
endmodule

/*
* @info Data Operation Sub-Module
*
* @author VLSI Lab, EE dept., Democritus University of Thrace
*
* @brief Used in the Data Cache, a provided microop picks the operation that will be used
*
* @param ADDR_W    : # of Address Bits
* @param DATA_W    : # of Data Bits
* @param MICROOP_W : # of Microoperation Bits
* @param BLOCK_W   : # of Cache Block Bits
* @param LOAD_ONLY : Instatiates the block only with the load operations
*/
module vdata_operation #(
    parameter ADDR_W    = 5  ,
    parameter DATA_W    = 256,
    parameter MICROOP_W = 7  ,
    parameter SIZE_W    = 6  ,
    parameter BLOCK_W   = 256
) (
    input  logic                 clk          ,
    input  logic                 valid_i      ,
    //Inputs
    input  logic [   ADDR_W-1:0] input_address,
    input  logic [2*BLOCK_W-1:0] input_block  ,
    input  logic [   DATA_W-1:0] input_data   ,
    input  logic [MICROOP_W-1:0] microop      ,
    input  logic [   SIZE_W-1:0] size         ,
    //Outputs
    output logic                 valid_exc    ,
    output logic [          3:0] exception    ,
    output logic [2*BLOCK_W-1:0] output_block ,
    output logic [   DATA_W-1:0] output_vector
);

    // #Internal Signals#
    logic [   ADDR_W+3:0] offset_ammount  ;
    logic [   SIZE_W+2:0] size_in_bits    ;
    logic [2*BLOCK_W-1:0] shifted_data    ;
    logic [   DATA_W-1:0] load_output_mask;
    logic [2*BLOCK_W-1:0] lower_mask      ;
    logic [2*BLOCK_W-1:0] upper_mask      ;
    logic [2*BLOCK_W-1:0] store_mask      ;
    logic [2*BLOCK_W-1:0] new_data        ;
    logic [2*BLOCK_W-1:0] new_block       ;

    assign valid_exc = 1'b0;
    assign exception = '0;
    //=======================================================
    // Mask for output data (LOADS)
    //=======================================================
    // Shift the input block to align the data to position 0
    assign offset_ammount = input_address << 3;
    assign shifted_data   = input_block >> offset_ammount;

    // Convert the size to number of bits
    assign size_in_bits  = size << 3; //convert bytes to bits

    // Mask for output data (LOADS)
    assign load_output_mask = ~('1 << size_in_bits);
    assign output_vector    = load_output_mask & shifted_data[DATA_W-1:0];


    //=======================================================
    // Mask for new memory block (STORES)
    //=======================================================
    assign lower_mask   = ~('1 << offset_ammount);
    assign upper_mask   = lower_mask << size_in_bits;
    assign store_mask   = upper_mask & lower_mask;
    // shift the data to the correct position inside the block
    assign new_data     = (input_data << offset_ammount) & store_mask;
    // zero-out the old data inside the input block
    assign new_block    = input_block & (~store_mask);
    // merge the old block with the new data
    assign output_block = new_block | new_data;


    //=======================================================
    // Maximum supported transaction size is equal/smaller than the configured cache line
    assert property (@(posedge clk) valid_i |-> (size_in_bits <= BLOCK_W)) else $warning("FATAL:vdata_operation: unsupported configuration");
    assert property (@(posedge clk) valid_i |-> ~$isunknown(|output_vector)) else $error("x-check:vdata_operation: output_vector");

endmodule

